function normalizeRole(role) { const value = String(role?.name || role || '').toUpperCase(); if (value.includes('SUBADMIN') || value.includes('SUBADMINISTRADOR')) return 'SUBADMIN'; if (value.includes('ADMIN')) return 'ADMIN'; if (value.includes('BIBLIOTECARIO') || value.includes('LIBRARIAN')) return 'BIBLIOTECARIO'; if (value.includes('PROFESOR') || value.includes('DOCENTE') || value.includes('TEACHER')) return 'PROFESOR'; if (value.includes('ESTUDIANTE') || value.includes('STUDENT')) return 'ESTUDIANTE'; if (value.includes('CLIENTE') || value.includes('USUARIO') || value.includes('USER')) return 'CLIENTE'; return 'INVITADO'; }
