function statusColor(status) { const value = loanStatus(status); if (value === 'Devuelto') return 'green'; if (value === 'Pendiente') return 'gold'; if (value === 'Cancelado') return 'red'; if (value === 'Vencido') return 'volcano'; return 'blue'; }
function userStatus(status) { return String(status || 'ACTIVE').toUpperCase() === 'SUSPENDED' ? 'SUSPENDED' : 'ACTIVE'; }
function userStatusLabel(status) { return userStatus(status) === 'SUSPENDED' ? 'Suspendido' : 'Activo'; }
function averageRating(book) { const ratings = Array.isArray(book?.ratings) ? book.ratings : []; if (ratings.length === 0) return 0; return ratings.reduce((sum, item) => sum + Number(item.rating || 0), 0) / ratings.length; }
function canRateBook(book, loans, currentUser) { if (!currentUser || !book) return false; return loans.some((loan) => loan.userId === currentUser.id && loan.bookId === book.id && loanStatus(loan.status) === 'Devuelto'); }
