function requestBadgeLabel(loan) { const status = loanStatus(loan?.status); if (status === 'Activo') return 'En préstamo'; if (status === 'Vencido') return 'Vencido'; return 'Solicitado'; }
function requestBadgeColor(loan) { const status = loanStatus(loan?.status); if (status === 'Activo') return 'blue'; if (status === 'Vencido') return 'volcano'; return 'green'; }
function getBookCover(book) { const imageUrl = String(book?.imageUrl || '').trim(); if (imageUrl) return imageUrl; const isbn = String(book?.isbn || '').replace(/[^0-9X]/gi, ''); return isbn ? `https://covers.openlibrary.org/b/isbn/${isbn}-L.jpg` : ''; }
function coverStyle(book) { const cover = getBookCover(book); return cover ? { backgroundImage: `linear-gradient(180deg, rgba(15,47,74,.05), rgba(15,47,74,.45)), url("${cover}")` } : undefined; }
function isSuspended(user) { return userStatus(user?.status) === 'SUSPENDED'; }
function formatCurrency(value) { return `$${Number(value || 0).toFixed(2)}`; }
function loanCostLabel(loan) { const discount = Number(loan?.discountPercent || 0); const base = Number(loan?.baseCost || 0); const finalCost = Number(loan?.finalCost ?? base); if (discount >= 100) return 'Gratis para profesor'; if (discount > 0) return `${formatCurrency(finalCost)} (${discount}% de descuento)`; return formatCurrency(finalCost); }
function daysUntil(date) { if (!date) return null; const today = new Date(); const dueDate = new Date(date); today.setHours(0, 0, 0, 0); dueDate.setHours(0, 0, 0, 0); return Math.max(0, Math.ceil((dueDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24))); }
