  function showMessage(text, type = 'info') { setMessage(text); setMessageType(type); }
  async function loadData() { setLoading(true); setMessage(''); const requests = [['books', api.get('/books'), setBooks], ['authors', api.get('/books/authors/list'), setAuthors], ['categories', api.get('/books/categories/list'), setCategories]]; if (canViewLoans && currentUser) requests.push(['loans', api.get('/loans'), setLoans], ['reservations', api.get('/loans/reservations'), setReservations]); else { setLoans([]); setReservations([]); } if (canViewUsers) requests.push(['users', api.get('/users'), setUsers]); else setUsers([]); if (canViewAdmin) requests.push(['roles', api.get('/roles'), setRoles], ['permissions', api.get('/permissions'), setPermissions]); else { setRoles([]); setPermissions([]); } const results = await Promise.allSettled(requests.map(([, request]) => request)); const failed = []; let authExpired = false; results.forEach((result, index) => { const [name, , setter] = requests[index]; if (result.status === 'fulfilled') setter(Array.isArray(result.value.data) ? result.value.data : []); else { const status = result.reason?.response?.status; if (currentUser && [401, 403].includes(status)) authExpired = true; failed.push(name); console.error('No se pudo cargar ' + name, result.reason); } }); if (authExpired) { localStorage.removeItem(tokenKey); localStorage.removeItem(sessionKey); setCurrentUser(null); setActiveView('inicio'); showMessage('Tu sesión venció. Inicia sesión nuevamente.', 'error'); setLoading(false); return; } if (failed.length > 0) showMessage('Algunos datos no pudieron cargarse. Inténtalo nuevamente.', 'error'); setLoading(false); }
